import { useState, useRef, useCallback } from "react";

// ── Embedded scene photos ─────────────────────────────────────────────────
const img12 = "data:image/png;base64,";
const img13 = "data:image/png;base64,";
const img14 = "data:image/png;base64,";
const img15 = "data:image/png;base64,";
const img16 = "data:image/png;base64,";
// ── Scene image map ───────────────────────────────────────────────────────
const IMG_MAP = { img12, img13, img14, img15, img16 };

// ── Scene + hotspot data ──────────────────────────────────────────────────
// Hotspot grid — each row is [id, label, x, y, w, h] in % of image.
// Verified non-overlapping per scene by visual inspection of each photo.
const HOME_SCENES = [
  {
    id: 1, title: "Making Pancakes", img: "img12",
    note: "The kitchen smells like vanilla and butter while I wait for bubbles to show up on my pancake. In the background, I can hear Mom stirring her tea and humming a little song. It's a quiet morning, and I'm just happy we're hanging out together while I cook.",
    hotspots: [
      // Left column: plates on shelf (x 0–14, y 22–52)
      { id:"h1", label:"The plates are on the shelf",  x: 0,  y: 22, w: 14, h: 30 },
      // Top-right: spice jars (x 55–100, y 0–32)
      { id:"h2", label:"The spices are on the shelf",  x: 55, y:  0, w: 45, h: 32 },
      // Centre torso / person (x 22–58, y 30–72)
      { id:"h3", label:"She is making pancakes",       x: 22, y: 30, w: 36, h: 42 },
      // Right mid: pot holder (x 65–84, y 42–65)
      { id:"h4", label:"I need the pot holder",        x: 65, y: 42, w: 19, h: 23 },
      // Bottom centre: stove & pan (x 22–76, y 72–96)
      { id:"h5", label:"I want to cook on the stove",  x: 22, y: 72, w: 54, h: 24 },
    ]
  },
  {
    id: 2, title: "Preparing Lunch", img: "img13",
    note: "Mom lifts her little one onto the counter so they can be close while she makes lunch. The baby watches with big curious eyes as the knife taps the cutting board. There's something really sweet about cooking together, even when the helper is too young to actually help.",
    hotspots: [
      // Top shelf: bowls & baskets (x 0–60, y 0–18)
      { id:"h1", label:"The bowls are on the shelf",   x:  0, y:  0, w: 60, h: 18 },
      // Left: knife block & utensils (x 0–16, y 28–65)
      { id:"h2", label:"I need a knife",               x:  0, y: 28, w: 16, h: 37 },
      // Centre-left: banana & basket (x 16–42, y 40–62)
      { id:"h3", label:"I want a banana",              x: 16, y: 40, w: 26, h: 22 },
      // Centre: baby on counter (x 42–72, y 10–62)
      { id:"h4", label:"The baby is on the counter",   x: 42, y: 10, w: 30, h: 52 },
      // Lower centre: cutting board & food (x 16–72, y 62–88)
      { id:"h5", label:"She is cutting the food",      x: 16, y: 62, w: 56, h: 26 },
    ]
  },
  {
    id: 3, title: "Family Time", img: "img14",
    note: "Everyone piled onto the sofa and the whole room filled up with noise and laughter. One of the girls grabbed mom's face and mom went along with it, laughing so hard her whole body shook. Dad held the other one tight and just watched, smiling like he couldn't believe how lucky he was.",
    hotspots: [
      // Far left: mom (x 0–24, y 14–88)
      { id:"h1", label:"Mom is laughing",              x:  0, y: 14, w: 24, h: 74 },
      // Centre-left: standing girl (x 24–50, y  0–72)
      { id:"h2", label:"She is climbing on mom",       x: 24, y:  0, w: 26, h: 72 },
      // Centre-right: dad's face & torso (x 50–76, y  4–60)
      { id:"h3", label:"Dad is smiling",               x: 50, y:  4, w: 26, h: 56 },
      // Right: dad hugging little girl (x 62–88, y 50–96)
      { id:"h4", label:"Dad is hugging her",           x: 62, y: 50, w: 26, h: 46 },
      // Top-right background: living room (x 76–100, y 0–44)
      { id:"h5", label:"They are in the living room",  x: 76, y:  0, w: 24, h: 44 },
    ]
  },
  {
    id: 4, title: "Bedtime Story", img: "img15",
    note: "The lamp throws a warm glow across the bed as Mom tucks everyone in close. She reads slowly, her voice soft and steady, and one of the kids keeps sneaking glances up at her face instead of the page. It's the best part of the day — that quiet moment before sleep when everything feels safe.",
    hotspots: [
      // Far left: lamp (x 0–20, y 0–80)
      { id:"h1", label:"Turn on the lamp",             x:  0, y:  0, w: 20, h: 80 },
      // Centre: mom & kids (x 20–62, y 0–65)
      { id:"h2", label:"Mom is reading to the kids",   x: 20, y:  0, w: 42, h: 65 },
      // Right: book (x 62–96, y 38–80)
      { id:"h3", label:"She is reading a book",        x: 62, y: 38, w: 34, h: 42 },
      // Lower centre: pillows & blanket (x 20–62, y 65–96)
      { id:"h4", label:"They are cosy in bed",         x: 20, y: 65, w: 42, h: 31 },
      // Top-right: window & curtains (x 68–96, y 0–36)
      { id:"h5", label:"It is dark outside",           x: 68, y:  0, w: 28, h: 36 },
    ]
  },
  {
    id: 5, title: "Dining Room", img: "img16",
    note: "The dining room is set up for a holiday meal, with greenery running down the middle of the table and candles glowing between the glasses. The geometric chandeliers hang low over everything, and the deer painting on the wall makes the whole room feel both cosy and a little grand. It's the kind of room that makes you want to slow down and stay a while.",
    hotspots: [
      // Left window + wreath (x 0–18, y 0–55)
      { id:"h1", label:"There is a wreath on the window", x: 0,  y:  0, w: 18, h: 55 },
      // Left chandelier (x 8–40, y 0–38)  — starts right of wreath column
      { id:"h2", label:"The chandelier is pretty",     x: 18, y:  0, w: 26, h: 38 },
      // Right chandelier + deer painting (x 44–82, y 0–42)
      { id:"h3", label:"I like the deer painting",     x: 44, y:  0, w: 38, h: 42 },
      // Right armchair (x 82–100, y 30–96)
      { id:"h4", label:"I want to sit in the chair",   x: 82, y: 30, w: 18, h: 66 },
      // Table & chairs — full lower band (x 18–82, y 42–96)
      { id:"h5", label:"I want to sit at the table",   x: 18, y: 42, w: 64, h: 54 },
    ]
  },
];

const OTHER_CATS = ["Work", "Businesses", "Family", "Shopping", "Transportation"];

// ── Main App ──────────────────────────────────────────────────────────────
export default function App() {
  const [activeCatId, setActiveCatId] = useState("home");
  const [activeSceneIdx, setActiveSceneIdx] = useState(0);
  const [selectedHotspot, setSelectedHotspot] = useState(null);
  const [noteOpen, setNoteOpen] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const speakRef = useRef(null);

  const scenes = HOME_SCENES; // extend later for other categories
  const scene = scenes[activeSceneIdx];

  const speak = useCallback((text) => {
    if (!("speechSynthesis" in window)) return;
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.rate = 0.92;
    u.onstart = () => setIsSpeaking(true);
    u.onend = () => setIsSpeaking(false);
    u.onerror = () => setIsSpeaking(false);
    window.speechSynthesis.speak(u);
  }, []);

  const stopSpeech = useCallback(() => {
    if ("speechSynthesis" in window) window.speechSynthesis.cancel();
    setIsSpeaking(false);
  }, []);

  const handleHotspot = (e, hs) => {
    e.stopPropagation();
    setNoteOpen(false);
    setSelectedHotspot(hs);
  };

  const handleDeselect = () => {
    setSelectedHotspot(null);
    setNoteOpen(false);
    stopSpeech();
  };

  const handlePlay = (e) => {
    e.stopPropagation();
    if (isSpeaking) {
      stopSpeech();
      return;
    }
    if (noteOpen) { speak(scene.note); return; }
    if (selectedHotspot) speak(selectedHotspot.label);
  };

  const handleNoteToggle = (e) => {
    e.stopPropagation();
    stopSpeech();
    setNoteOpen((prev) => !prev);
    setSelectedHotspot(null);
  };

  const handleCategoryClick = (id) => {
    setActiveCatId(id);
    setActiveSceneIdx(0);
    setSelectedHotspot(null);
    setNoteOpen(false);
    stopSpeech();
  };

  const handleThumbClick = (idx) => {
    setActiveSceneIdx(idx);
    setSelectedHotspot(null);
    setNoteOpen(false);
    stopSpeech();
  };

  return (
    <div
      onClick={handleDeselect}
      style={{
        fontFamily: "'Helvetica Neue', Arial, sans-serif",
        background: "#ececec",
        height: "100dvh",
        maxHeight: "100dvh",
        display: "flex",
        flexDirection: "column",
        userSelect: "none",
        overflow: "hidden",
        position: "fixed",
        inset: 0,
      }}
    >
      <style>{`
        .cat-tab {
          cursor: pointer;
          padding: 9px 16px;
          border-radius: 10px;
          font-size: clamp(12px, 1.2vw, 15px);
          font-weight: 500;
          background: #fff;
          border: 2px solid #ddd;
          transition: all 0.15s;
          white-space: nowrap;
          color: #333;
          line-height: 1.2;
        }
        .cat-tab:hover { background: #e8f0fe; border-color: #aac4f5; }
        .cat-tab.active {
          background: #fff;
          border: 2.5px solid #5b9bd5;
          color: #1a4a8a;
          font-weight: 700;
        }
        .cat-count {
          display: block;
          font-size: 11px;
          color: #7a9cc8;
          font-weight: 400;
          margin-top: 1px;
        }
        .thumb-item {
          cursor: pointer;
          border-radius: 8px;
          overflow: hidden;
          border: 3px solid transparent;
          transition: border 0.15s, transform 0.1s;
          flex-shrink: 0;
          background: #ccc;
        }
        .thumb-item:hover { transform: scale(1.02); border-color: #aac4f5; }
        .thumb-item.active { border-color: #5b9bd5; }
        .thumb-item img { width: 100%; height: clamp(70px, 8vw, 100px); object-fit: cover; display: block; }
        .hotspot-zone {
          position: absolute;
          border-radius: 6px;
          cursor: pointer;
          border: 2px solid rgba(255,255,255,0.5);
          transition: background 0.15s, border-color 0.15s;
          box-sizing: border-box;
        }
        .hotspot-zone:hover {
          background: rgba(255,255,255,0.15);
          border-color: rgba(255,255,255,0.75);
        }
        .hotspot-zone.selected {
          background: rgba(91,155,213,0.25);
          border-color: rgba(91,155,213,0.9);
          border-width: 2.5px;
        }
        .pencil-btn {
          position: absolute;
          top: 12px;
          left: 12px;
          width: 44px;
          height: 44px;
          border-radius: 10px;
          background: rgba(50,50,50,0.72);
          border: none;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: background 0.15s, transform 0.1s;
          z-index: 10;
          backdrop-filter: blur(4px);
        }
        .pencil-btn:hover { background: rgba(30,30,30,0.88); transform: scale(1.05); }
        .pencil-btn.active { background: rgba(91,155,213,0.85); }
        .play-btn {
          display: flex;
          align-items: center;
          gap: 7px;
          background: #fff;
          border: 2px solid #ccc;
          border-radius: 10px;
          padding: 9px 18px;
          font-size: 15px;
          font-weight: 600;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
          flex-shrink: 0;
          color: #222;
        }
        .play-btn:hover { background: #e8f4ff; border-color: #5b9bd5; }
        .play-btn:disabled { opacity: 0.45; cursor: default; }
        .add-btn {
          width: 48px; height: 48px;
          border-radius: 10px;
          background: #e8e8e8;
          border: 2px solid #ccc;
          font-size: 24px;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
          color: #888;
          transition: background 0.15s;
        }
        .add-btn:hover { background: #d0e4ff; border-color: #5b9bd5; color: #5b9bd5; }
        .add-scene {
          display: flex;
          align-items: center;
          justify-content: center;
          height: clamp(70px, 8vw, 100px);
          border: 2px dashed #bbb;
          border-radius: 8px;
          cursor: pointer;
          background: #f0f0f0;
          flex-shrink: 0;
          font-size: 26px;
          color: #bbb;
          transition: background 0.15s;
        }
        .add-scene:hover { background: #e0ecff; border-color: #5b9bd5; color: #5b9bd5; }
      `}</style>

      {/* ── Top bar ── */}
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: "#fff",
          borderBottom: "1px solid #ddd",
          padding: "10px 12px",
          display: "flex",
          alignItems: "center",
          gap: 8,
          overflowX: "auto",
        }}
      >
        {/* Profile icon */}
        <div style={{ width: 50, height: 50, borderRadius: 10, background: "#c5cfe8", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, border: "2px solid #aabce8" }}>
          <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="#4a6fa5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
            <circle cx="12" cy="7" r="4"/>
          </svg>
        </div>

        <button
          className={`cat-tab${activeCatId === "home" ? " active" : ""}`}
          onClick={() => handleCategoryClick("home")}
        >
          Home
          {activeCatId === "home" && <span className="cat-count">({scenes.length})</span>}
        </button>

        {OTHER_CATS.map((cat) => (
          <button
            key={cat}
            className={`cat-tab${activeCatId === cat.toLowerCase() ? " active" : ""}`}
            onClick={() => handleCategoryClick(cat.toLowerCase())}
          >
            {cat}
          </button>
        ))}

        <button className="add-btn" title="Add category">+</button>
      </div>

      {/* ── Main content ── */}
      <div style={{ flex: 1, display: "flex", overflow: "hidden", minHeight: 0, height: 0 }}>

        {/* Scene viewer */}
        <div style={{ flex: 1, position: "relative", background: "#111", minWidth: 0, display: "flex", flexDirection: "column" }}>
          {/* Image + hotspots */}
          <div style={{ flex: 1, position: "relative", overflow: "hidden" }}>
            <img
              src={IMG_MAP[scene.img]}
              alt={scene.title}
              style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
              draggable={false}
            />

            {scene.hotspots.map((hs) => (
              <div
                key={hs.id}
                className={`hotspot-zone${selectedHotspot?.id === hs.id ? " selected" : ""}`}
                style={{ left: `${hs.x}%`, top: `${hs.y}%`, width: `${hs.w}%`, height: `${hs.h}%` }}
                onClick={(e) => handleHotspot(e, hs)}
              >
              </div>
            ))}

            {/* Pencil / note button — all scenes */}
            <button
              className={`pencil-btn${noteOpen ? " active" : ""}`}
              onClick={handleNoteToggle}
              title={noteOpen ? "Close note" : "Read scene note"}
            >
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 20h9"/>
                <path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/>
              </svg>
            </button>
          </div>

          {/* Bottom bar */}
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "rgba(255,255,255,0.94)",
              backdropFilter: "blur(6px)",
              borderTop: "1px solid #ddd",
              padding: "10px 14px",
              display: "flex",
              alignItems: "center",
              gap: 12,
            }}
          >
            {/* Label display */}
            <div style={{
              flex: 1,
              minHeight: 42,
              background: "#fff",
              border: `1.5px solid ${noteOpen ? "#5b9bd5" : "#dde3ec"}`,
              borderRadius: 10,
              display: "flex",
              alignItems: "center",
              padding: "0 14px",
              fontSize: noteOpen ? 14 : 16,
              color: (noteOpen || selectedHotspot) ? "#1a3a6a" : "#aaa",
              fontWeight: noteOpen ? 400 : (selectedHotspot ? 600 : 400),
              fontStyle: (!noteOpen && !selectedHotspot) ? "italic" : "normal",
              letterSpacing: 0.2,
              lineHeight: noteOpen ? 1.5 : 1.3,
              transition: "color 0.15s, font-size 0.15s",
              overflowY: noteOpen ? "auto" : "hidden",
              maxHeight: noteOpen ? 80 : 42,
            }}>
              {noteOpen
                ? scene.note
                : selectedHotspot
                  ? selectedHotspot.label
                  : "Tap an area in the scene…"}
            </div>

            {/* Play / Stop button */}
            <button
              className="play-btn"
              onClick={handlePlay}
              disabled={!selectedHotspot && !noteOpen}
              style={isSpeaking ? { borderColor: "#e05555", color: "#e05555" } : {}}
            >
              {isSpeaking ? "Stop" : "Play"}
              {isSpeaking ? (
                <svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor" stroke="none">
                  <rect x="4" y="4" width="6" height="16" rx="1"/>
                  <rect x="14" y="4" width="6" height="16" rx="1"/>
                </svg>
              ) : (
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/>
                  <path d="M19.07 4.93a10 10 0 0 1 0 14.14"/>
                  <path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>
                </svg>
              )}
            </button>
          </div>
        </div>

        {/* Thumbnail strip */}
        <div
          onClick={(e) => e.stopPropagation()}
          style={{
            width: "clamp(110px, 13vw, 170px)",
            background: "#e2e2e2",
            borderLeft: "1px solid #ccc",
            display: "flex",
            flexDirection: "column",
            gap: 5,
            padding: "6px 6px",
            overflowY: "auto",
            flexShrink: 0,
          }}
        >
          {scenes.map((sc, idx) => (
            <div
              key={sc.id}
              className={`thumb-item${activeSceneIdx === idx ? " active" : ""}`}
              onClick={() => handleThumbClick(idx)}
            >
              <img src={IMG_MAP[sc.img]} alt={sc.title} />
            </div>
          ))}
          <div className="add-scene" title="Add scene">+</div>
        </div>
      </div>
    </div>
  );
}
